#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        for (int i = 0; i <= n; i++) {
            printf("%d %d %d %d\n", 0, i, n, n - i);
        }
    }
    return 0;
}

