code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            for (int i = 0; i <= n; i++) {
                System.out.println(0 + " " + i + " " + n + " " + (n - i));
            }
        }
    }
}

